import React from "react";

import hexToRGB from "../utils/hexToRGB";

export default (props) => (
  <div className="ColorSwatch" css={{
        margin: 5,
        padding: 20,
        height: 200,
        width: 200,
        backgroundColor: props.hex,
        color: props.dark ? "#f5f5f5" : "#070A0C",
        boxShadow: "0 10px 20px -8px rgba(0, 0, 0, .2)",
        border: `3px solid rgba(${props.dark ? '255, 255, 255' : '0, 0, 0'}, .01)`,
        borderRadius: 3,
        transform: "translateZ(0)",
        transition: "all .3s cubic-bezier(.175,.885,.32,1.275)",
        ":hover": {
            boxShadow: "0 15px 25px -8px rgba(0, 0, 0, .2)",
            transform: "translateY(-5px)",
        },
    }}>
        <div className="ColorSwatch-name" css={{
            position: "absolute",
        }}>
            { props.name }
        </div>
        <div className="ColorSwatch-codes" css={{
            position: "absolute",
            bottom: 20,
            fontSize: ".9em",
            fontFamily: "monospace",
        }}>
            <div className="ColorSwatch-hex-code">
                { props.hex }
            </div>
            <div className="ColorSwatch-rgb-code">
                RGB { hexToRGB(props.hex).join(' ') }
            </div>
        </div>
    </div>
);
